SELECT

FROM mall_goods_spu mall_goods_spu

	
		AND mall_goods_spu.`shelf` = #{query.shelf}
	
	
		AND mall_goods_spu.`category_second` = #{query.categorySecond}
	
	
		AND mall_goods_spu.`name` LIKE CONCAT('%', #{query.name}, '%')
	
	
		AND mall_goods_spu.`spu_code` = #{query.spuCode}

SELECT

FROM mall_goods_spu mall_goods_spu
WHERE mall_goods_spu.`id` = #{id}

